arguments.command:
# Verify all other addresses are in .text
for addr in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2c1a40; do
  llvm-objdump-18 --section-headers /tmp/symbols/libmonosgen-2.0.so 2>/dev/null | grep -E '^\s+[0-9]+' | awk -v target="$addr" '
  BEGIN { t = strtonum(target) }
  {
    a = strtonum("0x" $4)
    s = strtonum("0x" $3)
    if (t >= a && t < a+s) printf "%s → section: %s\n", target, $2
  }'
done

